add_action('template_redirect', function() {
    if (is_page('contact')) {
        while (ob_get_level()) ob_end_clean();
        header('Content-Type: text/html; charset=UTF-8');
        echo mosaic_inject_seo(mosaic_dynamic_nav(base64_decode('')), 'contact');
        exit;
    }
}, 1);